local LFightIdleBaseCtrl = LXImport(".LFightIdleBaseCtrl")

---@class LFightIdleHudCtrl:LFightIdleBaseCtrl
local LFightIdleHudCtrl = LxClass("LFightIdleHudCtrl", LFightIdleBaseCtrl)
-----------------------------------------------------------------
local CS = CS

local LFightIdleHud = LXImport("..Object.LFightIdleHud")

-----------------------------------------------------------------
function LFightIdleHudCtrl:LFightIdleHudCtrl()

end

function LFightIdleHudCtrl:InitHud()
	local uiFightRoot = LGameUI.GetUIFight()
	local hudRootTrans = CS.FindTrans(uiFightRoot,"UIHud")
	self._hudRootTrans = hudRootTrans
	local hudTemplateRoot = CS.FindTrans(hudRootTrans,"Template")
	self._hudTemplateRoot = hudTemplateRoot
	CS.ShowObject(hudTemplateRoot,false)

	self:InitTemplate()

	self._cacheHurtList = {}
	self._cacheCritList = {}
	self._cacheWorldList = {}
	self._cacheHealList = {}

	self._cacheNodeList = {}
	self._cacheHurtHeroList = {}

	---@type LFightIdleHud
	self._hudList = {}
end

function LFightIdleHudCtrl:InitTemplate()
	local hudRootTrans = self._hudRootTrans
	local hudTemplateRoot = self._hudTemplateRoot
	local mainScene = GF.GetMainScene()
	local btHudTemplate = LxResUtil.NewObject(mainScene:GetHudAssetObject("BtHud"))
	local btHudTemplateTrans = btHudTemplate.transform
	CS.SetParentTrans(btHudTemplateTrans,hudTemplateRoot)
	self._btHudTemplateTrans = btHudTemplateTrans

	local btHudNodeTemplate = LxResUtil.NewObject(mainScene:GetHudAssetObject("BtHudNode"))
	local btHudNodeTemplateTrans = btHudNodeTemplate.transform
	CS.SetParentTrans(btHudNodeTemplateTrans,hudTemplateRoot)
	self._btHudNodeTemplateGo = btHudNodeTemplateTrans.gameObject

	local btHurt = CS.FindTrans(btHudTemplateTrans,"BtHurt").gameObject
	local btCrit = CS.FindTrans(btHudTemplateTrans,"BtCrit").gameObject
	local btWorld = CS.FindTrans(btHudTemplateTrans,"BtWorld").gameObject
	local btHeal = CS.FindTrans(btHudTemplateTrans,"BtHeal").gameObject
	local btHurtHero = CS.FindTrans(btHudTemplateTrans,"BtHurtHero").gameObject

	self._dicTemplateMap = {
		[LFightIdleConst.HUD_HURT] = btHurt,
		[LFightIdleConst.HUD_CRIT] = btCrit,
		[LFightIdleConst.HUD_WORLD] = btWorld,
		[LFightIdleConst.HUD_HEAL] = btHeal,
		[LFightIdleConst.HUD_BTNODE] = self._btHudNodeTemplateGo,
		[LFightIdleConst.HUD_HURT_HERO] = btHurtHero,
	}

	self.btHud = nil
	self.btHudNode = nil
end

-----------------------------------------------------------------
function LFightIdleHudCtrl:CreateHud(obj,hudData)
	local hud = LFightIdleHud:New()
	hud:InitHud(self:GetHudRootTrans(),obj,hudData,self)
	self:AddHud(hud)
	return hud
end

function LFightIdleHudCtrl:AddHud(hud)
	table.insert(self._hudList,hud)
end
-----------------------------------------------------------------
function LFightIdleHudCtrl:GetHudRootTrans()
	return self._hudRootTrans
end

function LFightIdleHudCtrl:MakeHudTransFromCache(hudType)
	local cacheList = self:GetHudCacheList(hudType)
	if not cacheList then return nil end
	if #cacheList > 0 then
		local cacheGameObject = table.remove(cacheList)
		return cacheGameObject.transform
	else
		local tempalteGo = self._dicTemplateMap[hudType]
		if not tempalteGo then return end
		local cloneGo = LxResUtil.NewObject(tempalteGo)

		CS.SetParentTrans(cloneGo.transform,self._hudTemplateRoot)

		return cloneGo.transform
	end
end

function LFightIdleHudCtrl:ReturnHudTransToCache(hudType,trans)
	local cacheList = self:GetHudCacheList(hudType)
	if not cacheList then return false end
	CS.SetParentTrans(trans,self._hudTemplateRoot)
	table.insert(cacheList,trans.gameObject)
	return true
end

function LFightIdleHudCtrl:GetHudCacheList(hudType)
	if hudType ==  LFightIdleConst.HUD_HURT then
		return self._cacheHurtList
	elseif hudType == LFightIdleConst.HUD_CRIT then
		return self._cacheCritList
	elseif hudType == LFightIdleConst.HUD_WORLD then
		return self._cacheWorldList
	elseif hudType == LFightIdleConst.HUD_HEAL then
		return self._cacheHealList
	elseif hudType == LFightIdleConst.HUD_BTNODE then
		return self._cacheNodeList
	elseif hudType == LFightIdleConst.HUD_HURT_HERO then
		return self._cacheHurtHeroList
	end
end
-----------------------------------------------------------------
function LFightIdleHudCtrl:OnRun(time)
	local delIndex = {}
	local hudList = self._hudList
	for k,v in ipairs(hudList) do
		if not v:OnRun(time) then
			table.insert(delIndex,k)
		end
	end

	for k=#delIndex,1,-1 do
		local hud = table.remove(hudList,delIndex[k])
		hud:Destroy()
	end
end

-----------------------------------------------------------------
function LFightIdleHudCtrl:ClearHudCache(cacheList)
	if not cacheList then return end
	for k,v in ipairs(cacheList) do
		LxResUtil.DestroyObject(v)
	end
end

function LFightIdleHudCtrl:Destroy()
	if self._hudList then
		for k, v in ipairs(self._hudList) do
			v:Destroy()
		end
		self._hudList = nil
	end

	self:ClearHudCache(self._cacheHurtList)
	self:ClearHudCache(self._cacheHealList)
	self:ClearHudCache(self._cacheCritList)
	self:ClearHudCache(self._cacheWorldList)
	self:ClearHudCache(self._cacheNodeList)
	self:ClearHudCache(self._cacheHurtHeroList)
	LxResUtil.DestroyObject(self._btHudTemplateTrans.gameObject)
	LxResUtil.DestroyObject(self._btHudNodeTemplateGo.gameObject)
	table.removeall(self)
end

return LFightIdleHudCtrl